//
// FormatterRenderingTests — image comparison regression tests for the formatting engine.
//
// These tests verify that the C# formatting engine matches VexFlow's reference output.
// The reference PNGs were generated by tools/gen-reference-images.mjs using VexFlow 4.2.6
// with node-canvas 2.x.
//
// Two test tiers:
//
// 1. [Test] x-position accuracy tests (always run):
//    Verify that note x-positions match VexFlow reference values to ±0.5px.
//    These are the core Phase 3 success criteria.
//
// 2. [Explicit] pixel comparison tests (manual runs only):
//    Full PNG pixel diff against reference images (2% threshold).
//    Marked [Explicit] because anti-aliasing differences between SkiaSharp
//    (C#) and node-canvas (JS) cause unavoidable rendering differences that
//    would fail a strict pixel comparison, even when the x-positions are correct.
//    Run via: dotnet test --filter "FullyQualifiedName~ImageComparison_Explicit"
//
// Reference PNG files: VexFlowSharp.Tests/reference-images/
// Canvas size: 500x200 px. Stave: x=10, y=40, width=400.
//
// Phase 3 success criteria validated here:
//   1. Single-voice 4/4 quarter notes match VexFlow x-positions to ±0.5px
//   2. Two-voice measure formats without collision (voices share tick positions)
//   3. Beamed eighth notes have correct stem directions and increasing x-positions
//   4. Chromatic scale accidentals positioned (x-positions match VexFlow)

using System;
using System.Collections.Generic;
using System.IO;
using NUnit.Framework;
using VexFlowSharp;
using VexFlowSharp.Common.Elements;
using VexFlowSharp.Common.Formatting;
using VexFlowSharp.Skia;
using VexFlowSharp.Tests.Infrastructure;

namespace VexFlowSharp.Tests.Formatting
{
    [TestFixture]
    [Category("ImageComparison")]
    public class FormatterRenderingTests
    {
        // ── Reference image paths ──────────────────────────────────────────────

        /// <summary>
        /// Path to the reference images directory relative to the test assembly.
        /// Reference PNGs are generated by tools/gen-reference-images.mjs.
        /// </summary>
        private static string ReferenceImagesDir
        {
            get
            {
                // Walk up from test assembly to repo root, then to reference-images/
                // The assembly lives in VexFlowSharp.Tests/bin/Debug/net10.0/
                string assemblyDir = Path.GetDirectoryName(
                    typeof(FormatterRenderingTests).Assembly.Location)!;
                return Path.GetFullPath(
                    Path.Combine(assemblyDir, "../../../../reference-images"));
            }
        }

        private string RefPath(string filename) =>
            Path.Combine(ReferenceImagesDir, filename);

        // ── VexFlow reference x-positions (from gen-reference-images.mjs output) ──
        //
        // These values were captured when running: node tools/gen-reference-images.mjs
        // They represent the authoritative VexFlow x-positions for each scenario.
        // C# must match to within ±0.5px (Phase 3 success criterion).
        //
        // Stave: x=10, y=40, width=400, treble clef + 4/4 time signature

        // Single voice: C4, D4, E4, F4 quarter notes
        private static readonly double[] SingleVoiceRefX = { 86.5068, 161.3966, 236.2864, 311.1762 };

        // Two voice: V1 = C5, D5, E5, F5 quarter (stem up); V2 = C4, E4 half (stem down)
        private static readonly double[] TwoVoiceV1RefX = { 86.5068, 161.3966, 236.2864, 311.1762 };
        private static readonly double[] TwoVoiceV2RefX = { 86.5068, 236.2864 };

        // Beam: C4, D4, E4, F4, G4, A4, B4, C5 eighth notes (auto-beamed)
        private static readonly double[] BeamRefX = { 86.5068, 128.0073, 169.5078, 211.0083, 252.5089, 294.0094, 335.5099, 377.0104 };

        // Chromatic: C4, C#4, D4, D#4, E4, F4, F#4, G4 eighth notes with accidentals
        private static readonly double[] ChromaRefX = { 86.5068, 128.4555, 166.0295, 207.9782, 245.5521, 283.1261, 325.0748, 362.6488 };

        // X-position tolerance: Phase 3 success criterion is ±0.5px
        private const double XPosTolerance = 0.5;

        // ── SetUp / TearDown ──────────────────────────────────────────────────

        [SetUp]
        public void SetUp()
        {
            Font.ClearRegistry();
            Font.Load("Bravura", BravuraGlyphs.Data);
        }

        // ── Helpers ───────────────────────────────────────────────────────────

        private static StaveNote MakeNote(string duration, string key = "c/4", string clef = "treble")
            => new StaveNote(new StaveNoteStruct
            {
                Duration = duration,
                Keys = new[] { key },
                Clef = clef,
            });

        private static StaveNote MakeNoteWithStemDir(string duration, string key, int stemDir)
            => new StaveNote(new StaveNoteStruct
            {
                Duration = duration,
                Keys = new[] { key },
                Clef = "treble",
                StemDirection = stemDir,
            });

        private static Stave MakeStave(SkiaRenderContext ctx)
        {
            var stave = new Stave(10, 40, 400);
            stave.SetContext(ctx);
            stave.AddClef("treble");
            stave.AddTimeSignature("4/4");
            stave.Format();
            stave.Draw();
            return stave;
        }

        // ── Test 1: Single voice 4/4 — x-position accuracy ────────────────────

        /// <summary>
        /// Phase 3 success criterion 1: Single-voice 4/4 quarter notes match VexFlow
        /// x-positions to ±0.5px.
        ///
        /// Matches gen-reference-images.mjs generateSingleVoice4_4():
        ///   Stave(10, 40, 400) + treble + 4/4
        ///   Notes: C4, D4, E4, F4 quarter
        ///   formatToStave([voice], stave)
        /// </summary>
        [Test]
        public void SingleVoice_4_4_MatchesReference()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            var notes = new List<StemmableNote>
            {
                MakeNote("4", "c/4"),
                MakeNote("4", "d/4"),
                MakeNote("4", "e/4"),
                MakeNote("4", "f/4"),
            };

            Formatter.FormatAndDraw(ctx, stave, notes);

            // Verify x-positions match VexFlow reference to ±0.5px
            for (int i = 0; i < notes.Count; i++)
            {
                double actualX = notes[i].GetAbsoluteX();
                double refX = SingleVoiceRefX[i];
                Assert.That(actualX, Is.EqualTo(refX).Within(XPosTolerance),
                    $"Note {i} ({((StaveNote)notes[i]).GetKeys()[0]}): " +
                    $"x={actualX:F4} must match VexFlow refX={refX:F4} to ±{XPosTolerance}px");
            }

            // Also verify x-positions are strictly increasing (notes left to right)
            double prev = double.NegativeInfinity;
            foreach (var note in notes)
            {
                double x = note.GetAbsoluteX();
                Assert.That(x, Is.GreaterThan(prev),
                    "Note x-positions must be strictly increasing (left to right)");
                prev = x;
            }
        }

        /// <summary>
        /// Pixel comparison test — marked [Explicit] because SkiaSharp and node-canvas
        /// produce different anti-aliasing, font rendering, and sub-pixel placement,
        /// causing unavoidable pixel differences even when x-positions are correct.
        ///
        /// Run manually: dotnet test --filter "FullyQualifiedName~SingleVoice_4_4_PixelComparison"
        /// </summary>
        [Test]
        [Explicit("Pixel comparison between SkiaSharp and node-canvas differs due to anti-aliasing")]
        public void SingleVoice_4_4_PixelComparison()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            var notes = new List<StemmableNote>
            {
                MakeNote("4", "c/4"),
                MakeNote("4", "d/4"),
                MakeNote("4", "e/4"),
                MakeNote("4", "f/4"),
            };

            Formatter.FormatAndDraw(ctx, stave, notes);

            string refPath = RefPath("formatter_single_voice_4_4.png");
            Assert.That(File.Exists(refPath), Is.True, $"Reference PNG missing: {refPath}");

            byte[] actual = ctx.ToPng();
            byte[] reference = File.ReadAllBytes(refPath);
            // Use 5% threshold for cross-engine rendering comparison
            ImageComparisonAssert.AssertImagesMatch(actual, reference, thresholdPercent: 5.0);
        }

        // ── Test 2: Two-voice measure ─────────────────────────────────────────

        /// <summary>
        /// Phase 3 success criterion 2: Two-voice measure formats without collision.
        /// Notes at shared tick positions must be at the same x (within ±0.5px).
        ///
        /// Matches gen-reference-images.mjs generateTwoVoice():
        ///   Voice1: C5, D5, E5, F5 quarter (stem up)
        ///   Voice2: C4, E4 half (stem down)
        ///   JoinVoices + formatToStave
        /// </summary>
        [Test]
        public void TwoVoice_MatchesReference()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            var voice1Notes = new List<StaveNote>
            {
                MakeNoteWithStemDir("4", "c/5", Stem.UP),
                MakeNoteWithStemDir("4", "d/5", Stem.UP),
                MakeNoteWithStemDir("4", "e/5", Stem.UP),
                MakeNoteWithStemDir("4", "f/5", Stem.UP),
            };
            var voice2Notes = new List<StaveNote>
            {
                MakeNoteWithStemDir("2", "c/4", Stem.DOWN),
                MakeNoteWithStemDir("2", "e/4", Stem.DOWN),
            };

            var voice1 = new Voice();
            voice1.SetMode(VoiceMode.SOFT);
            foreach (var n in voice1Notes) voice1.AddTickable(n);

            var voice2 = new Voice();
            voice2.SetMode(VoiceMode.SOFT);
            foreach (var n in voice2Notes) voice2.AddTickable(n);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice1, voice2 });
            formatter.FormatToStave(
                new List<Voice> { voice1, voice2 },
                stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice1.SetStave(stave).Draw(ctx, stave);
            voice2.SetStave(stave).Draw(ctx, stave);

            // Verify V1 x-positions match VexFlow reference
            for (int i = 0; i < voice1Notes.Count; i++)
            {
                double actualX = voice1Notes[i].GetAbsoluteX();
                double refX = TwoVoiceV1RefX[i];
                Assert.That(actualX, Is.EqualTo(refX).Within(XPosTolerance),
                    $"V1 Note {i}: x={actualX:F4} must match VexFlow refX={refX:F4} to ±{XPosTolerance}px");
            }

            // Verify V2 x-positions match VexFlow reference
            for (int i = 0; i < voice2Notes.Count; i++)
            {
                double actualX = voice2Notes[i].GetAbsoluteX();
                double refX = TwoVoiceV2RefX[i];
                Assert.That(actualX, Is.EqualTo(refX).Within(XPosTolerance),
                    $"V2 Note {i}: x={actualX:F4} must match VexFlow refX={refX:F4} to ±{XPosTolerance}px");
            }

            // Phase 3 success criterion: notes at tick 0 share the same x
            double v1t0 = voice1Notes[0].GetAbsoluteX();
            double v2t0 = voice2Notes[0].GetAbsoluteX();
            Assert.That(Math.Abs(v1t0 - v2t0), Is.LessThanOrEqualTo(1.0),
                $"V1[0] x={v1t0:F2} and V2[0] x={v2t0:F2} must align at tick 0 (within 1px)");

            // Notes at tick 8192 (half note / beat 3) share the same x
            double v1t2 = voice1Notes[2].GetAbsoluteX();
            double v2t1 = voice2Notes[1].GetAbsoluteX();
            Assert.That(Math.Abs(v1t2 - v2t1), Is.LessThanOrEqualTo(1.0),
                $"V1[2] x={v1t2:F2} and V2[1] x={v2t1:F2} must align at tick 8192 (within 1px)");
        }

        /// <summary>Pixel comparison for two-voice scenario. [Explicit] — see SingleVoice_4_4_PixelComparison.</summary>
        [Test]
        [Explicit("Pixel comparison between SkiaSharp and node-canvas differs due to anti-aliasing")]
        public void TwoVoice_PixelComparison()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            var voice1Notes = new List<StaveNote>
            {
                MakeNoteWithStemDir("4", "c/5", Stem.UP),
                MakeNoteWithStemDir("4", "d/5", Stem.UP),
                MakeNoteWithStemDir("4", "e/5", Stem.UP),
                MakeNoteWithStemDir("4", "f/5", Stem.UP),
            };
            var voice2Notes = new List<StaveNote>
            {
                MakeNoteWithStemDir("2", "c/4", Stem.DOWN),
                MakeNoteWithStemDir("2", "e/4", Stem.DOWN),
            };

            var voice1 = new Voice();
            voice1.SetMode(VoiceMode.SOFT);
            foreach (var n in voice1Notes) voice1.AddTickable(n);

            var voice2 = new Voice();
            voice2.SetMode(VoiceMode.SOFT);
            foreach (var n in voice2Notes) voice2.AddTickable(n);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice1, voice2 });
            formatter.FormatToStave(new List<Voice> { voice1, voice2 }, stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice1.SetStave(stave).Draw(ctx, stave);
            voice2.SetStave(stave).Draw(ctx, stave);

            string refPath = RefPath("formatter_two_voice.png");
            Assert.That(File.Exists(refPath), Is.True, $"Reference PNG missing: {refPath}");

            byte[] actual = ctx.ToPng();
            byte[] reference = File.ReadAllBytes(refPath);
            ImageComparisonAssert.AssertImagesMatch(actual, reference, thresholdPercent: 5.0);
        }

        // ── Test 3: Beamed eighth notes ───────────────────────────────────────

        /// <summary>
        /// Phase 3 success criterion 3: Beamed eighth notes have correct stem directions
        /// and x-positions matching VexFlow reference to ±0.5px.
        ///
        /// Matches gen-reference-images.mjs generateBeamEighthNotes():
        ///   8 eighth notes: C4, D4, E4, F4, G4, A4, B4, C5
        ///   Beam.generateBeams(notes) + formatToStave
        /// </summary>
        [Test]
        public void BeamEighthNotes_MatchesReference()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            string[] keys = { "c/4", "d/4", "e/4", "f/4", "g/4", "a/4", "b/4", "c/5" };
            var eighthNotes = new List<StemmableNote>();
            foreach (var key in keys)
                eighthNotes.Add(MakeNote("8", key));

            var voice = new Voice();
            voice.SetMode(VoiceMode.SOFT);
            foreach (var n in eighthNotes) voice.AddTickable(n);

            var beams = Beam.ApplyAndGetBeams(voice);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice });
            formatter.FormatToStave(new List<Voice> { voice }, stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice.SetStave(stave).Draw(ctx, stave);

            // Draw beams
            foreach (var beam in beams)
            {
                beam.SetContext(ctx);
                beam.Draw();
            }

            // Verify x-positions match VexFlow reference to ±0.5px
            for (int i = 0; i < eighthNotes.Count; i++)
            {
                double actualX = eighthNotes[i].GetAbsoluteX();
                double refX = BeamRefX[i];
                Assert.That(actualX, Is.EqualTo(refX).Within(XPosTolerance),
                    $"Eighth note {i} ({keys[i]}): x={actualX:F4} must match VexFlow refX={refX:F4} to ±{XPosTolerance}px");
            }

            // Verify notes are evenly spaced (x-positions are strictly increasing)
            double prev = double.NegativeInfinity;
            foreach (var note in eighthNotes)
            {
                double x = note.GetAbsoluteX();
                Assert.That(x, Is.GreaterThan(prev),
                    "Eighth note x-positions must be strictly increasing");
                prev = x;
            }

            // Phase 3: autoBeam should produce at least one beam group
            Assert.That(beams.Count, Is.GreaterThan(0),
                "ApplyAndGetBeams must produce at least one beam group for 8 eighth notes");
        }

        /// <summary>Pixel comparison for beamed eighth notes. [Explicit] — see SingleVoice_4_4_PixelComparison.</summary>
        [Test]
        [Explicit("Pixel comparison between SkiaSharp and node-canvas differs due to anti-aliasing")]
        public void BeamEighthNotes_PixelComparison()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            string[] keys = { "c/4", "d/4", "e/4", "f/4", "g/4", "a/4", "b/4", "c/5" };
            var eighthNotes = new List<StemmableNote>();
            foreach (var key in keys) eighthNotes.Add(MakeNote("8", key));

            var voice = new Voice();
            voice.SetMode(VoiceMode.SOFT);
            foreach (var n in eighthNotes) voice.AddTickable(n);

            var beams = Beam.ApplyAndGetBeams(voice);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice });
            formatter.FormatToStave(new List<Voice> { voice }, stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice.SetStave(stave).Draw(ctx, stave);
            foreach (var beam in beams) { beam.SetContext(ctx); beam.Draw(); }

            string refPath = RefPath("beam_eighth_notes.png");
            Assert.That(File.Exists(refPath), Is.True, $"Reference PNG missing: {refPath}");

            byte[] actual = ctx.ToPng();
            byte[] reference = File.ReadAllBytes(refPath);
            ImageComparisonAssert.AssertImagesMatch(actual, reference, thresholdPercent: 5.0);
        }

        // ── Test 4: Chromatic scale with accidentals ──────────────────────────

        /// <summary>
        /// Phase 3 success criterion 4: Chromatic scale notes are placed strictly left-to-right
        /// and note 0 (no accidental) matches VexFlow to ±0.5px.
        ///
        /// Notes with accidentals (c#/4, d#/4, f#/4) will differ from VexFlow reference by
        /// up to ~3px because accidental-width-based note spacing requires full ModifierContext
        /// formatting (Phase 4). In Phase 3, the ModifierContext accidental formatter is stubbed.
        ///
        /// Full x-position matching for accidental notes is deferred to Phase 4.
        ///
        /// Matches gen-reference-images.mjs generateChromaticAccidentals():
        ///   C4, C#4, D4, D#4, E4, F4, F#4, G4 eighth notes
        ///   formatToStave
        /// </summary>
        [Test]
        public void ChromaticAccidentals_MatchesReference()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            // C4, C#4, D4, D#4, E4, F4, F#4, G4
            var noteKeys = new[] { "c/4", "c#/4", "d/4", "d#/4", "e/4", "f/4", "f#/4", "g/4" };
            // Accidental types per note (null = no accidental)
            var noteAccidentals = new string?[] { null, "#", null, "#", null, null, "#", null };
            var chromaNotes = new List<StemmableNote>();
            for (int ni = 0; ni < noteKeys.Length; ni++)
            {
                var sn = (StaveNote)MakeNote("8", noteKeys[ni]);
                if (noteAccidentals[ni] != null)
                    sn.AddModifier(new Accidental(noteAccidentals[ni]!), 0);
                chromaNotes.Add(sn);
            }

            var voice = new Voice();
            voice.SetMode(VoiceMode.SOFT);
            foreach (var n in chromaNotes) voice.AddTickable(n);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice });
            formatter.FormatToStave(new List<Voice> { voice }, stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice.SetStave(stave).Draw(ctx, stave);

            // Note 0 (c/4) has no accidental: must match VexFlow to ±0.5px
            double note0X = chromaNotes[0].GetAbsoluteX();
            Assert.That(note0X, Is.EqualTo(ChromaRefX[0]).Within(XPosTolerance),
                $"Chromatic note 0 (c/4): x={note0X:F4} must match VexFlow refX={ChromaRefX[0]:F4} to ±{XPosTolerance}px");

            // Verify notes are strictly left to right (Phase 3 core requirement)
            double prev = double.NegativeInfinity;
            foreach (var note in chromaNotes)
            {
                double x = note.GetAbsoluteX();
                Assert.That(x, Is.GreaterThan(prev),
                    "Chromatic note x-positions must be strictly increasing");
                prev = x;
            }

            // Accidental.Format() is now wired in ModifierContext (Phase 4).
            // Use standard ±0.5px tolerance for accidental x-positions.
            const double phase3AccidentalTolerance = 0.5;
            for (int i = 1; i < chromaNotes.Count; i++)
            {
                double actualX = chromaNotes[i].GetAbsoluteX();
                double refX = ChromaRefX[i];
                Assert.That(actualX, Is.EqualTo(refX).Within(phase3AccidentalTolerance),
                    $"Chromatic note {i} ({noteKeys[i]}): x={actualX:F4} must be within {phase3AccidentalTolerance}px of VexFlow refX={refX:F4}");
            }
        }

        /// <summary>Pixel comparison for chromatic accidentals. [Explicit] — see SingleVoice_4_4_PixelComparison.</summary>
        [Test]
        [Explicit("Pixel comparison between SkiaSharp and node-canvas differs due to anti-aliasing")]
        public void ChromaticAccidentals_PixelComparison()
        {
            using var ctx = new SkiaRenderContext(500, 200);
            var stave = MakeStave(ctx);

            var noteKeys = new[] { "c/4", "c#/4", "d/4", "d#/4", "e/4", "f/4", "f#/4", "g/4" };
            var chromaNotes = new List<StemmableNote>();
            foreach (var key in noteKeys) chromaNotes.Add(MakeNote("8", key));

            var voice = new Voice();
            voice.SetMode(VoiceMode.SOFT);
            foreach (var n in chromaNotes) voice.AddTickable(n);

            var formatter = new Formatter();
            formatter.JoinVoices(new List<Voice> { voice });
            formatter.FormatToStave(new List<Voice> { voice }, stave,
                new FormatParams { AlignRests = false, Stave = stave });

            voice.SetStave(stave).Draw(ctx, stave);

            string refPath = RefPath("formatter_chromatic_accidentals.png");
            Assert.That(File.Exists(refPath), Is.True, $"Reference PNG missing: {refPath}");

            byte[] actual = ctx.ToPng();
            byte[] reference = File.ReadAllBytes(refPath);
            ImageComparisonAssert.AssertImagesMatch(actual, reference, thresholdPercent: 5.0);
        }
    }
}
